"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[421738],{750105:e=>{e.exports=JSON.parse('{"tag":{"label":"companion","permalink":"/dst-api-webdocs/docs/tags/companion","allTagsPath":"/dst-api-webdocs/docs/tags","count":16,"items":[{"id":"game-scripts/prefabs/bernie_active","title":"Bernie Active","description":"Represents the active, playable form of Bernie \u2014 a small companion creature that can transform into inactive or larger forms, managing health, movement, and inventory interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_active"},{"id":"game-scripts/prefabs/bernie_big","title":"Bernie Big","description":"A large companion boss entity that manages combat behavior, AI taunting, skill-based stat adjustments, and planar allegiance visual/artistic effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_big"},{"id":"game-scripts/prefabs/boatrace_spectator_dragonling","title":"Boatrace Spectator Dragonling","description":"A flying companion entity that follows the race indicator during boat races, reacting to leaks and checkpoints in the environment.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_spectator_dragonling"},{"id":"game-scripts/prefabs/critters","title":"Critters","description":"A factory system for creating companion critters with AI, hunger mechanics, sleeping behavior, and optional special abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/critters"},{"id":"game-scripts/prefabs/eyeturret","title":"Eyeturret","description":"A deployable companion turret that automatically engages enemies within range, emits a dynamic light, and shares aggro with nearby turrets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eyeturret"},{"id":"game-scripts/prefabs/glommer","title":"Glommer","description":"A flying lunar-aligned companion entity that follows the player, enters sleep cycles, periodically spawns fuel items, and adjusts sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommer"},{"id":"game-scripts/prefabs/hutch","title":"Hutch","description":"Manages the Chester hutch entity, a companion that transforms between forms based on inventory batteries and provides light, damage reflection, and sanity effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hutch"},{"id":"game-scripts/brains/kitcoonbrain","title":"Kitcoonbrain","description":"Manages the AI behavior of a kitcoon, handling owner following, combat avoidance, playful interactions with other kitcoons and toys, and minigame observation.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/kitcoonbrain"},{"id":"game-scripts/prefabs/lavaarena_abigail","title":"Lavaarena Abigail","description":"A prefabricated entity instance for a ghostly variant of Abigail used exclusively in the Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_abigail"},{"id":"game-scripts/prefabs/lavaarena_bernie","title":"Lavaarena Bernie","description":"Creates a non-player companion entity for the Lava Arena event that serves as a revivable stand-in for the player, accessible only to entities with the \\"bernie_reviver\\" tag.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_bernie"},{"id":"game-scripts/prefabs/lavaarena_elemental","title":"Lavaarena Elemental","description":"Creates and configures the lava arena elemental entity, a flying companion with specific physics, collision, and network behavior for lava arena scenarios.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_elemental"},{"id":"game-scripts/prefabs/lavae_pet","title":"Lavae Pet","description":"Manages the behavior, stats, and interactions of the Lavae pet companion in DST, including hunger-based heat/light regulation, sleep cycles, and ability to accept ashes for feeding.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavae_pet"},{"id":"game-scripts/prefabs/polly_rogers","title":"Polly Rogers","description":"Provides the definition and shared logic for two companion creatures: a flying bird (Polly Rogers) and a salt-shedding amphibious dog (Salty Dog), each with distinct behaviors, appearances, and interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/polly_rogers"},{"id":"game-scripts/prefabs/storage_robot","title":"Storage Robot","description":"Manages the behavior and state of the Storage Robot, a companion entity that collects and stores items from the world using fuel-based operation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/storage_robot"},{"id":"game-scripts/brains/wobycommon","title":"Wobycommon","description":"Provides shared AI behavior logic and utility functions for Woby, a companion entity in Don\'t Starve Together, including fetching, foraging, ammo retrieval, courier, and minigame watching.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobycommon"},{"id":"game-scripts/brains/wobysmallbrain","title":"Wobysmallbrain","description":"Implements the AI behavior tree for the Woby small variant, handling combat avoidance, playful interaction with other critters, affection towards its owner, and helper actions such as fetching and foraging.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobysmallbrain"}],"unlisted":false}}')}}]);